import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def test_interleaved_archive_restore_preserves_each_documents_high_water_mark():
    db = sqlite3.connect(":memory:")
    db.row_factory = sqlite3.Row
    db.executescript((ROOT / "sql/001_schema.sql").read_text())
    db.executescript((ROOT / "sql/002_head_triggers.sql").read_text())
    db.executemany(
        "INSERT INTO documents(document_id, title) VALUES (?, ?)",
        [("policy", "Policy"), ("runbook", "Runbook")],
    )
    db.executemany(
        """INSERT INTO document_versions
           (document_id, version_id, logical_clock, body, import_batch)
           VALUES (?, ?, ?, ?, ?)""",
        [
            ("policy", "p20", 20, "draft", "live-a"),
            ("runbook", "r4", 4, "boot", "live-a"),
            ("policy", "p35", 35, "ratified", "live-b"),
            ("runbook", "r7", 7, "recovered", "live-c"),
            ("policy", "p30", 30, "archive replay", "archive-restore"),
        ],
    )

    heads = {
        row["document_id"]: (row["version_id"], row["logical_clock"])
        for row in db.execute(
            "SELECT document_id, version_id, logical_clock FROM document_heads"
        )
    }
    assert heads == {"policy": ("p35", 35), "runbook": ("r7", 7)}

    visible = {
        row["document_id"]: (row["version_id"], row["body"], row["logical_clock"])
        for row in db.execute((ROOT / "sql/read_current.sql").read_text())
    }
    assert visible == {
        "policy": ("p35", "ratified", 35),
        "runbook": ("r7", "recovered", 7),
    }
